sections.preambleSelect:
Definir alfa vPerIni;
Definir alfa vPerFim;
Definir alfa vSqlAux;
Definir alfa ESolAte;

@ Verifica se a data inicial é menor que a final e ambas diferentes de zero @
Se ((EPerIni > EPerFim) ou (EPerIni = 0) ou (EPerFim = 0))
Inicio
   Mensagem(Erro, "A Data Inicial deve ser menor que a Data Final e ambas diferentes de zero! [&OK]");
   Cancel(1);
Fim;

ConverteDataBanco(EPerIni,vPerIni);
ConverteDataBanco(EPerFim,vPerFim);

vSqlAux = "(R110MED.DatAte >= " + vPerIni + " AND  R110MED.DatAte <= " + vPerFim + ")";
InsClauSqlWhere("Detalhe_Medicamentos",vSqlAux);

@ Tratamento para listar somente solicitações atendidas ou todas @
Se (ESolAte = "S")
Inicio
   vSqlAux = " AND R110MED.IndSol = 'S'";
   InsClauSqlWhere("Detalhe_Medicamentos",vSqlAux);
Fim;

/* -----------------------------------------------------------------
    VERIFICA NA DEFINIÇÃO DO MEDICINA SE É USADO O SUBGRUPO DO CID
   ----------------------------------------------------------------- */
Definir Cursor CDef;
Definir Alfa xUsaSub;

xUsaSub = "N";
xNumEmp = EmpAtu;
CDef.SQL "SELECT APRCID FROM R110DEF WHERE NUMEMP = :xNumEmp";
CDef.AbrirCursor();
Se (CDef.Achou)
  {
  xUsaSub = CDef.AprCid;
  }
CDef.FecharCursor();

sections.initialization:
/*
 define as listas que serão utilizadas para totalização dos medicamentos por forma de apresentação
 acumulando os medicamentos administrados e doados
*/
Definir Lista LTotMedAdm;

LTotMedAdm.DefinirCampos();
LTotMedAdm.AdicionarCampo("Med",alfa);
LTotMedAdm.AdicionarCampo("Tip",alfa);
LTotMedAdm.AdicionarCampo("Qtd",numero);
LTotMedAdm.AdicionarCampo("Dat",data);
LTotMedAdm.EfetivarCampos();

Definir Lista LTotMedDoa;

LTotMedDoa.DefinirCampos();
LTotMedDoa.AdicionarCampo("Med",alfa);
LTotMedDoa.AdicionarCampo("Tip",alfa);
LTotMedDoa.AdicionarCampo("Qtd",numero);
LTotMedDoa.AdicionarCampo("Dat",data);
LTotMedDoa.EfetivarCampos();

bands.onBeforePrint:
Definir alfa xDesAprAdm;
Definir alfa xDesAprDoa;
Definir cursor Cur_R110Apr;
Definir Numero xCodApr;
Definir alfa EAprDoa;

@ Tratamento para apresentar quantidade doada @
Se (EAprDoa = "S")
Inicio
  AlteraControle("Cadastro010","Imprimir","Verdadeiro");
  AlteraControle("DesAprDoa","Imprimir","Verdadeiro");
Fim;
Senao
Inicio
  AlteraControle("Cadastro010","Imprimir","Falso");
  AlteraControle("DesAprDoa","Imprimir","Falso");
Fim;

@ Limpa as variáveis @
xDesAprAdm = "";
xDesAprDoa = "";

/*
 utiliza-se o mesmo cursor para retornar a descrição da forma de apresentação do medicamento
 administrado e do medicamento doado
*/
Cur_R110Apr.SQL "SELECT DESAPR FROM R110APR WHERE CODAPR=:xCodApr";

@ Busca a descrição do medicamento administrado @
xCodApr = R110MED.CodApr;

Cur_R110Apr.AbrirCursor();
Se (Cur_R110Apr.Achou)
Inicio
  xDesAprAdm = Cur_R110Apr.DesApr;  
Fim;
Cur_R110Apr.FecharCursor();

@ Busca a descrição do medicamento doado @
xCodApr = R110MED.CodApd;

Cur_R110Apr.AbrirCursor();
Se (Cur_R110Apr.Achou)
Inicio
  xDesAprDoa = Cur_R110Apr.DesApr;  
Fim;
Cur_R110Apr.FecharCursor();

@ Exibe o resultado nos campos descrição @
AlteraControle("DesAprAdm","Descrição",xDesAprAdm);
AlteraControle("DesAprDoa","Descrição",xDesAprDoa);

bands.onAfterPrint:
Definir alfa xDesAprAdm;
Definir alfa xDesAprDoa;
Definir alfa EAprRec; @ Apresentar Recomendação @
Definir alfa EAprAno; @ Apresentar Anotação @
Definir alfa EAprAtr; @ Apresentar Atendente que receitou remédio @
Definir alfa EAprAta; @ Apresentar Atendente que administrou remédio @
Definir alfa vAteRec; @ Nome do Atendente que receitou remédio @
Definir alfa vAteAdm; @ Nome do Atendente que administrou remédio @
Definir cursor Cur_R108TAT;
Definir Numero vCodAte;

Cur_R108TAT.SQL "SELECT NomAte FROM R108TAT WHERE CodAte=:vCodAte";

@ Listar atendente que receitou / administrou @
Se ((EAprAtr = "S") ou (EAprAta = "S"))
Inicio
  Se ((EAprAtr = "S") e (R110MED.CodAte <> 0))
  Inicio
    vCodAte = R110MED.CodAte;
    vAteRec = "";

    Cur_R108TAT.AbrirCursor();
    Se (Cur_R108TAT.Achou)
      vAteRec = Cur_R108TAT.NomAte;
    Cur_R108TAT.FecharCursor();  

  Fim;

  Se ((EAprAta = "S") e (R110MED.AteAdm <> 0))
  Inicio
    vCodAte = R110MED.AteAdm;
    vAteAdm = "";

    Cur_R108TAT.AbrirCursor();
    Se (Cur_R108TAT.Achou)
      vAteAdm = Cur_R108TAT.NomAte;
    Cur_R108TAT.FecharCursor();  
  Fim;

  AlteraControle("DescRespReceita","Descrição",vAteRec);
  AlteraControle("DescRespAdmin","Descrição",vAteAdm);
  ListaSecao("Adicional_Lista_Rec_Adm");
Fim;

Se ((EAprRec = "S") e ((R110MED.ObsAdm <> "") e (R110MED.ObsAdm <> " ")))
Inicio
  AlteraControle("MemoRecomenda","Justificado","Verdadeiro");
  ListaSecao("Adicional_Recomendacao");
Fim;

Se ((EAprAno = "S") e ((R110MED.AnoAdm <> "") e (R110MED.AnoAdm <> " ")))
Inicio
  AlteraControle("MemoAnota","Justificado","Verdadeiro");
  ListaSecao("Adicional_Anotacao");
Fim;

/*********************************************************
          TOTALIZADOR MEDICAMENTO ADMINISTRADO
 *********************************************************/
@ Verificar antes se houve administração de remédio @
Se ((xDesAprAdm <> "") e (R110MED.QtdApl <> 0))
inicio
  LTotMedAdm.Chave("Med;Tip;Dat");
  LTotMedAdm.SetarChave();
  LTotMedAdm.Med = R110REM.NomRem;
  LTotMedAdm.Tip = xDesAprAdm;
  LTotMedAdm.Dat = R110MED.DatAte;

  @ Se encontrar o medicamento/apresentação na lista, altera o valor, senão inclui @
  Se (LTotMedAdm.VaiParaChave())
  inicio
    LTotMedAdm.Editar();
    LTotMedAdm.Qtd = LTotMedAdm.Qtd + R110MED.QtdApl;
    LTotMedAdm.Gravar();
  fim;
  Senao
  inicio
    LTotMedAdm.Adicionar();
    LTotMedAdm.Med = R110REM.NomRem;
    LTotMedAdm.Tip = xDesAprAdm;
    LTotMedAdm.Dat = R110MED.DatAte;
    LTotMedAdm.Qtd = R110MED.QtdApl;
    LTotMedAdm.Gravar();
  fim;
fim;

/*********************************************************
          TOTALIZADOR MEDICAMENTO DOADO
 *********************************************************/
@ Verificar antes se houve doação de remédio @
Se ((xDesAprDoa <> "") e (R110MED.QtdDoa <> 0))
inicio
  LTotMedDoa.Chave("Med;Tip;Dat");
  LTotMedDoa.SetarChave();
  LTotMedDoa.Med = R110REM.NomRem;
  LTotMedDoa.Tip = xDesAprDoa;
  LTotMedDoa.Dat = R110MED.DatAte;

  @ Se encontrar o medicamento/apresentação na lista, altera o valor, senão inclui @
  Se (LTotMedDoa.VaiParaChave())
  inicio
    LTotMedDoa.Editar();
    LTotMedDoa.Qtd = LTotMedDoa.Qtd + R110MED.QtdDoa;
    LTotMedDoa.Gravar();
  fim;
  Senao
  inicio
    LTotMedDoa.Adicionar();
    LTotMedDoa.Med = R110REM.NomRem;
    LTotMedDoa.Tip = xDesAprDoa;
    LTotMedDoa.Dat = R110MED.DatAte;
    LTotMedDoa.Qtd = R110MED.QtdDoa;
    LTotMedDoa.Gravar();
  fim;
fim;
/*********************************************************/

