bands.onBeforePrint:
Definir alfa EAprDoa;

Se (EAprDoa = "S")
Inicio
  AlteraControle("Descricao007","Imprimir","Verdadeiro");
  AlteraControle("FDoa","Imprimir","Verdadeiro");
Fim;
Senao
Inicio
  AlteraControle("Descricao007","Imprimir","Falso");
