bands.onAfterPrint:
Definir alfa xDescApres;

xDescApres = "";
FTotTipo   = 0;

FAdm = 0;
FDoa = 0;

Tem  = LTotMedAdm.Primeiro();
Teve = Tem;

Enquanto (Tem = 1)
inicio
  @ Se é a mesma forma de administração mas outra data, deve acumular @
  Se (xDescApres = LTotMedAdm.Tip){
    FTotTipo = FTotTipo + LTotMedAdm.Qtd;
    FAdm = FTotTipo;
    LTotMedDoa.Chave("Med;Tip");
    LTotMedDoa.SetarChave();
    LTotMedDoa.Med = LTotMedAdm.Med;
    LTotMedDoa.Tip = LTotMedAdm.Tip;

    Enquanto (LTotMedDoa.VaiParaChave())
    {
      FDoa = FDoa + LTotMedDoa.Qtd;
      LTotMedDoa.Excluir();
    }    
  }
  Senao
  inicio
    @ A primeira vez não lista nada @
    Se (xDescApres <> "")
    inicio
      AlteraControle("DescApres","Descrição",xDescApres);
      ListaSecao("Adicional_Total_Med");
      FDoa = 0;
      FAdm = 0;
    fim;
    xDescApres = LTotMedAdm.Tip;
    FTotTipo = LTotMedAdm.Qtd;
    FAdm = FTotTipo;

    LTotMedDoa.Chave("Med;Tip");
    LTotMedDoa.SetarChave();
    LTotMedDoa.Med = LTotMedAdm.Med;
    LTotMedDoa.Tip = LTotMedAdm.Tip;
    Enquanto (LTotMedDoa.VaiParaChave())
    {
      FDoa = FDoa + LTotMedDoa.Qtd;
      LTotMedDoa.Excluir();
    }    

  fim;
  Tem = LTotMedAdm.Proximo();
fim;

@ Lista o último da lista @
Se (Teve = 1)
inicio
  AlteraControle("DescApres","Descrição",xDescApres);
  ListaSecao("Adicional_Total_Med");
  FDoa = 0;
  FAdm = 0;
fim;

@ Limpa a lista em memória @
LTotMedAdm.Limpar();

/* Navega por todos os registros da lista obtendo os valores dos campos */
Definir alfa EAprDoa;

@ Tratamento para apresentar quantidade doada @
Se (EAprDoa = "S")
inicio
  xDescApres = "";
  FTotTipo   = 0;

  Tem = LTotMedDoa.Primeiro();
  Teve = Tem;

  Enquanto (Tem = 1)
  inicio
    Se (xDescApres = LTotMedDoa.Tip){
      FTotTipo = FTotTipo + LTotMedDoa.Qtd;
      FDoa = FTotTipo;
    }
    Senao
    inicio
      @ A primeira vez não lista nada @
      Se (xDescApres <> "")
      inicio
        AlteraControle("DescApres","Descrição",xDescApres);
        ListaSecao("Adicional_Total_Med");
        FDoa = 0;
        FAdm = 0;        
      fim;
      xDescApres = LTotMedDoa.Tip;
      FTotTipo   = LTotMedDoa.Qtd;
      FDoa = FTotTipo;
    fim;
    Tem = LTotMedDoa.Proximo();
  fim;
  Se (Teve = 1)
  inicio
    AlteraControle("DescApres","Descrição",xDescApres);
    ListaSecao("Adicional_Total_Med");
    FDoa = 0;
    FAdm = 0;
  fim;
fim;
LTotMedDoa.Limpar();

UltimoRegistro ("Detalhe_Medicamentos", IsEof);
Se (IsEof = 0)
  SaltarPagina();

